import re
import json

raw = _input.first().json["output"]

match = re.search(r"```json\s*(.*?)\s*```", raw, flags=re.S)
if not match:
    raise ValueError("No JSON block found in output")

json_text = match.group(1).strip()
parsed = json.loads(json_text)

results = []

if isinstance(parsed, list):
    for item in parsed:
        if not isinstance(item, dict):
            raise ValueError(f"Array element is not a dict: {item}")
        platform = item.get("Platform")
        product_link = item.get("Product link")
        message = item.get("Message")

        if platform is None:
            raise ValueError(f"No 'Platform' key in: {item}")

        results.append({
            "Platform": platform,
            "Product link": product_link,
            "Message": message
        })

elif isinstance(parsed, dict):
    results = [parsed]
else:
    raise ValueError(f"Unexpected JSON type: {type(parsed)}")

return [{"json": r} for r in results]
